import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { interviewAPI } from '../utils/api';
import InterviewForm from '../components/InterviewForm';
import VoiceRecorder from '../components/VoiceRecorder';

function Interview() {
  const { state, dispatch } = useApp();
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState('setup'); // setup, interview, analysis
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [currentResponse, setCurrentResponse] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [error, setError] = useState('');

  const handleStart = async (userData) => {
    dispatch({ type: 'SET_USER', payload: userData });
    dispatch({ type: 'RESET_INTERVIEW' });
    dispatch({ type: 'SET_LOADING', payload: true });

    try {
      const result = await interviewAPI.getQuestions(userData.role);
      dispatch({ type: 'SET_INTERVIEW_QUESTIONS', payload: result.questions });
      setCurrentStep('interview');
    } catch (err) {
      setError('Failed to load interview questions');
    } finally {
      dispatch({ type: 'SET_LOADING', payload: false });
    }
  };

  const handleTranscript = (transcript) => {
    setCurrentResponse(transcript);
  };

  const handleNextQuestion = () => {
    if (currentResponse.trim()) {
      dispatch({
        type: 'ADD_INTERVIEW_RESPONSE',
        payload: {
          question: state.interviewData.questions[currentQuestionIndex],
          answer: currentResponse.trim()
        }
      });
    }

    if (currentQuestionIndex < state.interviewData.questions.length - 1) {
      setCurrentQuestionIndex(currentQuestionIndex + 1);
      setCurrentResponse('');
      setIsListening(false);
    } else {
      finishInterview();
    }
  };

  const finishInterview = async () => {
    setCurrentStep('analysis');
    dispatch({ type: 'SET_LOADING', payload: true });

    // Create transcript
    const transcript = state.interviewData.responses
      .map(item => `Q: ${item.question}\nA: ${item.answer}`)
      .join('\n\n');

    if (currentResponse.trim()) {
      const finalTranscript = transcript + `\n\nQ: ${state.interviewData.questions[currentQuestionIndex]}\nA: ${currentResponse.trim()}`;
      dispatch({ type: 'SET_INTERVIEW_TRANSCRIPT', payload: finalTranscript });

      try {
        const result = await interviewAPI.analyze(finalTranscript);
        dispatch({ type: 'SET_INTERVIEW_ANALYSIS', payload: result.analysis });
        navigate('/dashboard');
      } catch (err) {
        setError('Failed to analyze interview');
      } finally {
        dispatch({ type: 'SET_LOADING', payload: false });
      }
    }
  };

  const toggleListening = () => {
    setIsListening(!isListening);
  };

  if (currentStep === 'setup') {
    return (
      <div className="min-h-screen bg-gray-50 py-12">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-12">
            <h1 className="text-4xl font-bold text-gray-900 mb-4">
              AI Mock Interview
            </h1>
            <p className="text-lg text-gray-600">
              Practice your interview skills with our AI-powered voice interview
            </p>
          </div>

          {error && (
            <div className="mb-8 bg-red-50 border border-red-200 rounded-md p-4 max-w-md mx-auto">
              <p className="text-sm text-red-700 text-center">{error}</p>
            </div>
          )}

          <InterviewForm onStart={handleStart} />
        </div>
      </div>
    );
  }

  if (currentStep === 'interview') {
    return (
      <div className="min-h-screen bg-gray-50 py-12">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="mb-8">
            <div className="flex justify-between items-center mb-4">
              <h1 className="text-2xl font-bold text-gray-900">
                Mock Interview - {state.user.name || 'Candidate'}
              </h1>
              <span className="text-sm text-gray-500">
                Question {currentQuestionIndex + 1} of {state.interviewData.questions.length}
              </span>
            </div>

            {/* Progress Bar */}
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div
                className="bg-primary-600 h-2 rounded-full transition-all duration-300"
                style={{
                  width: `${((currentQuestionIndex + 1) / state.interviewData.questions.length) * 100}%`
                }}
              ></div>
            </div>
          </div>

          <div className="grid lg:grid-cols-2 gap-8">
            {/* Question */}
            <div className="bg-white rounded-lg shadow-sm p-8">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Interview Question
              </h2>
              <div className="bg-primary-50 border border-primary-200 rounded-lg p-6">
                <p className="text-lg text-gray-800">
                  {state.interviewData.questions[currentQuestionIndex]}
                </p>
              </div>

              <div className="mt-6 flex justify-between">
                <button
                  onClick={() => {
                    if (currentQuestionIndex > 0) {
                      setCurrentQuestionIndex(currentQuestionIndex - 1);
                      setCurrentResponse('');
                      setIsListening(false);
                    }
                  }}
                  disabled={currentQuestionIndex === 0}
                  className="px-4 py-2 text-gray-600 border border-gray-300 rounded-md hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Previous
                </button>

                <button
                  onClick={handleNextQuestion}
                  className="px-6 py-2 bg-primary-600 text-white rounded-md hover:bg-primary-700"
                >
                  {currentQuestionIndex === state.interviewData.questions.length - 1
                    ? 'Finish Interview'
                    : 'Next Question'}
                </button>
              </div>
            </div>

            {/* Voice Recorder */}
            <VoiceRecorder
              onTranscript={handleTranscript}
              isListening={isListening}
              onToggleListening={toggleListening}
            />
          </div>
        </div>
      </div>
    );
  }

  if (currentStep === 'analysis') {
    return (
      <div className="min-h-screen bg-gray-50 py-12">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600 mx-auto mb-4"></div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">
              Analyzing Your Interview...
            </h2>
            <p className="text-gray-600">
              Our AI is processing your responses and preparing detailed feedback
            </p>
          </div>
        </div>
      </div>
    );
  }

  return null;
}

export default Interview;
